// Parametric honeycomb / vent panel
// A flat rectangular panel perforated with a repeating cutout grid (hex / square /
// round), with an optional solid border frame. Tunable via the Customizer panel.
const { Manifold } = api;

const p = api.params({
  width:     { type: 'number',  default: 80, min: 20, max: 300, step: 1, unit: 'mm', label: 'Panel width' },
  height:    { type: 'number',  default: 60, min: 20, max: 300, step: 1, unit: 'mm', label: 'Panel height' },
  thickness: { type: 'number',  default: 3,  min: 1,  max: 20,  step: 0.5, unit: 'mm', label: 'Panel thickness' },
  cell:      { type: 'number',  default: 8,  min: 2,  max: 40,  step: 0.5, unit: 'mm', label: 'Cell size', help: 'Across-flats size of each opening' },
  wall:      { type: 'number',  default: 1.6, min: 0.4, max: 10, step: 0.1, unit: 'mm', label: 'Wall thickness', help: 'Material left between openings' },
  shape:     { type: 'select',  default: 'hex', options: [
                 { value: 'hex', label: 'Hexagon' },
                 { value: 'square', label: 'Square' },
                 { value: 'round', label: 'Round' },
               ], label: 'Cell shape' },
  border:    { type: 'boolean', default: true, label: 'Solid border frame' },
  borderW:   { type: 'number',  default: 5, min: 0, max: 40, step: 0.5, unit: 'mm', label: 'Border width' },
});

// --- derive grid geometry from the chosen cell size + wall -------------------
const pitch = p.cell + p.wall;                 // center-to-center spacing
const overcut = p.thickness + 2;               // make cutters poke through both faces
const frame = p.border ? Math.max(p.borderW, p.wall) : p.wall; // inset where cells may live

// Region the openings are allowed to occupy (panel minus the frame margin).
const innerW = p.width  - 2 * frame;
const innerH = p.height - 2 * frame;

// The solid panel, centered on the origin in XY, sitting z = 0..thickness.
const panel = Manifold.cube([p.width, p.height, p.thickness], true)
  .translate([0, 0, p.thickness / 2]);

// If the inner region is too small to fit even one opening, just return the
// solid panel (still a valid single manifold).
if (innerW < p.cell || innerH < p.cell) {
  return panel;
}

// --- one cutter for a single cell ------------------------------------------
function oneCell() {
  if (p.shape === 'square') {
    return Manifold.cube([p.cell, p.cell, overcut], true);
  }
  if (p.shape === 'round') {
    // Facet count scaled to hole size: a 2mm vent hole doesn't need 128 facets,
    // and a grid of thousands of them would explode the triangle count. Clamp to
    // a smooth-enough range (16..64) instead of inheriting the global preset.
    const seg = Math.max(16, Math.min(64, Math.round(p.cell * 4)));
    return Manifold.cylinder(overcut, p.cell / 2, p.cell / 2, seg).translate([0, 0, -overcut / 2]);
  }
  // hex: a 6-sided cylinder. cell = across-flats, so circumradius = af / sqrt(3).
  const r = p.cell / Math.sqrt(3);
  return Manifold.cylinder(overcut, r, r, 6).translate([0, 0, -overcut / 2]);
}

// --- tile the cutter across a hex-packed grid -------------------------------
// Hex packing: odd rows offset by half a pitch, rows spaced by pitch * sqrt(3)/2.
const cells = [];
const rowStep = p.shape === 'hex' ? pitch * Math.sqrt(3) / 2 : pitch;
const nCols = Math.max(1, Math.floor(innerW / pitch));
const nRows = Math.max(1, Math.floor(innerH / rowStep));

const cutter = oneCell();
const halfW = (nCols - 1) * pitch / 2;
const halfH = (nRows - 1) * rowStep / 2;

for (let row = 0; row < nRows; row++) {
  const y = row * rowStep - halfH;
  const stagger = p.shape === 'hex' && row % 2 === 1 ? pitch / 2 : 0;
  for (let col = 0; col < nCols; col++) {
    let x = col * pitch - halfW + stagger;
    // keep staggered cells from poking out past the inner region
    if (Math.abs(x) + p.cell / 2 > innerW / 2) continue;
    cells.push(cutter.translate([x, y, p.thickness / 2]));
  }
}

if (cells.length === 0) return panel;

const holes = Manifold.union(cells);
return panel.subtract(holes);
